/* Affirm' — scroll-scrubbed signing hands
   Frame sequences generated with Higgsfield (Seedance 2.0, start→end frame),
   scrubbed on a <canvas> indexed by scroll progress. */

const AFFIRMATIONS = [
  "My hands shape the life I imagine.",
  "I am fluent in my own becoming.",
  "I speak, even in silence.",
  "Every gesture moves me forward.",
  "I am the author and the alphabet.",
  "What I affirm, I become.",
];

/* CLIPS is generated by the frame-extraction step — counts must match frames/ */
const CLIPS = [
  { dir: "frames/clip1", count: 61 },
  { dir: "frames/clip2", count: 61 },
  { dir: "frames/clip3", count: 61 },
  { dir: "frames/clip4", count: 61 },
  { dir: "frames/clip5", count: 61 },
  { dir: "frames/clip6", count: 61 },
];

const reducedMotion = matchMedia("(prefers-reduced-motion: reduce)").matches;

/* ---------- clock ---------- */
{
  const timeEl = document.getElementById("clock-time");
  const zoneEl = document.getElementById("clock-zone");
  const tick = () => {
    const d = new Date();
    timeEl.textContent =
      String(d.getHours()).padStart(2, "0") + ":" + String(d.getMinutes()).padStart(2, "0");
    const off = -d.getTimezoneOffset() / 60;
    zoneEl.textContent = "GMT" + (off >= 0 ? "+" : "") + off;
  };
  tick();
  setInterval(tick, 15000);
}

/* ---------- marquee ---------- */
{
  const track = document.getElementById("marquee-track");
  const seq = AFFIRMATIONS.map((a) => `<span class="slash">\\</span>${a}`).join("");
  track.innerHTML = seq + seq; /* doubled for the -50% loop */
}

/* ---------- frame preloading ---------- */

const frames = []; /* flat, global timeline */
const clipOffsets = [];
let totalFrames = 0;
for (const c of CLIPS) {
  clipOffsets.push(totalFrames);
  totalFrames += c.count;
}
frames.length = totalFrames;

let loadedCount = 0;
let firstClipReady = false;
const loaderEl = document.getElementById("scrub-loader");
const loaderPct = document.getElementById("loader-pct");

function frameUrl(clip, i) {
  return `${clip.dir}/f${String(i + 1).padStart(4, "0")}.webp`;
}

function loadClip(ci) {
  const clip = CLIPS[ci];
  const promises = [];
  for (let i = 0; i < clip.count; i++) {
    const gi = clipOffsets[ci] + i;
    promises.push(
      new Promise((res) => {
        const img = new Image();
        img.decoding = "async";
        img.onload = () => {
          frames[gi] = img;
          loadedCount++;
          if (!firstClipReady) {
            loaderPct.textContent = Math.round((loadedCount / CLIPS[0].count) * 100) + "%";
          }
          res();
        };
        img.onerror = res; /* keep last drawn frame on gaps */
        img.src = frameUrl(clip, i);
      })
    );
  }
  return Promise.all(promises);
}

(async () => {
  await loadClip(0);
  firstClipReady = true;
  loaderEl.style.display = "none";
  requestDraw();
  for (let ci = 1; ci < CLIPS.length; ci++) await loadClip(ci);
})();

/* ---------- canvas scrub ---------- */

const canvas = document.getElementById("hands-canvas");
const ctx = canvas.getContext("2d");
const scrubSection = document.querySelector(".scrub");
const quoteEl = document.getElementById("scrub-quote");
const numEl = document.getElementById("scrub-num");
const hintEl = document.getElementById("scrub-hint");

let current = 0; /* smoothed frame position */
let target = 0;
let drawnIndex = -1;
let rafPending = false;

function sizeCanvas() {
  const dpr = Math.min(devicePixelRatio || 1, 2);
  canvas.width = Math.round(canvas.clientWidth * dpr);
  canvas.height = Math.round(canvas.clientHeight * dpr);
  drawnIndex = -1;
  requestDraw();
}
addEventListener("resize", sizeCanvas);

function nearestLoaded(idx) {
  if (frames[idx]) return frames[idx];
  for (let d = 1; d < totalFrames; d++) {
    if (frames[idx - d]) return frames[idx - d];
    if (frames[idx + d]) return frames[idx + d];
  }
  return null;
}

function draw(idx) {
  const img = nearestLoaded(idx);
  if (!img) return;
  const cw = canvas.width, ch = canvas.height;
  ctx.fillStyle = "#F5F5F3";
  ctx.fillRect(0, 0, cw, ch);
  /* contain-fit, anchored slightly low — hands rise from the bottom */
  const s = Math.min(cw / img.width, ch / img.height);
  const w = img.width * s, h = img.height * s;
  ctx.drawImage(img, (cw - w) / 2, ch - h - (ch - h) * 0.35, w, h);
  drawnIndex = idx;
}

/* ---------- quote reveal ---------- */

let activeSeg = -1;

function setSegment(seg) {
  if (seg === activeSeg) return;
  activeSeg = seg;
  numEl.textContent = String(seg + 1).padStart(2, "0");
  quoteEl.innerHTML = AFFIRMATIONS[seg]
    .split(" ")
    .map((w) => `<span class="w">${w}</span>`)
    .join(" ");
}

function updateWords(within) {
  const words = quoteEl.children;
  const n = words.length;
  /* all words revealed by 70% of the segment */
  const shown = Math.floor(Math.min(1, within / 0.7) * n + 0.0001);
  for (let i = 0; i < n; i++) words[i].classList.toggle("on", i < shown);
}

/* ---------- scroll wiring ---------- */

function onScroll() {
  const rect = scrubSection.getBoundingClientRect();
  const runway = rect.height - innerHeight;
  const p = Math.min(1, Math.max(0, -rect.top / runway));
  target = p * (totalFrames - 1);

  const segF = Math.min(0.999999, p) * CLIPS.length;
  const seg = Math.floor(segF);
  setSegment(seg);
  updateWords(segF - seg);

  hintEl.style.opacity = p > 0.02 ? "0" : "1";
  requestDraw();
}
addEventListener("scroll", onScroll, { passive: true });

function requestDraw() {
  if (rafPending) return;
  rafPending = true;
  requestAnimationFrame(step);
}

function step() {
  rafPending = false;
  const ease = reducedMotion ? 1 : 0.16;
  current += (target - current) * ease;
  if (Math.abs(target - current) < 0.5) current = target;
  const idx = Math.round(current);
  if (idx !== drawnIndex) draw(idx);
  if (current !== target) requestDraw();
}

/* ---------- statement word reveal ---------- */

for (const el of document.querySelectorAll(".reveal-words")) {
  el.innerHTML = el.textContent
    .trim()
    .split(/\s+/)
    .map((w) => `<span class="w">${w}</span>`)
    .join(" ");
  const words = [...el.children];
  const io = new IntersectionObserver(
    (entries) => {
      if (!entries[0].isIntersecting) return;
      words.forEach((w, i) => setTimeout(() => w.classList.add("on"), reducedMotion ? 0 : i * 28));
      io.disconnect();
    },
    { threshold: 0.4 }
  );
  io.observe(el);
}

/* ---------- boot ---------- */
sizeCanvas();
setSegment(0);
onScroll();
